      "content": "const express = require('express');
const service = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = service.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  try {
    const project = service.createProject(req.body.name);
    res.status(201).json({ project });
  } catch (error) {
    res.status(400).json({ error: { code: 'INVALID_NAME', message: error.message } });
  }
});

router.get('/:projectId/tasks', (req, res) => {
  const tasks = service.getTasksByProjectId(req.params.projectId);
  if (!tasks) {
    return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ tasks });
});

module.exports = router;
