      "content": "const express = require('express');
const service = require('./service');

const router = express.Router();

router.post('/:projectId', (req, res) => {
  try {
    const task = service.createTask(req.params.projectId, req.body.title);
    res.status(201).json({ task });
  } catch (error) {
    res.status(400).json({ error: { code: 'INVALID_TITLE', message: error.message } });
  }
});

router.patch('/:projectId/:taskId', (req, res) => {
  try {
    const task = service.updateTaskStatus(req.params.projectId, req.params.taskId, req.body.status);
    res.json({ task });
  } catch (error) {
    res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: error.message } });
  }
});

router.get('/:projectId/:taskId/comments', (req, res) => {
  const comments = service.getCommentsByTaskId(req.params.projectId, req.params.taskId);
  if (!comments) {
    return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ comments });
});

module.exports = router;
